      const nf = 1 / (near - far);
      o[10] = (far + near) * nf;
      o[14] = 2 * far * near * nf;
    } else {
      o[10] = -1;
      o[14] = -2 * near;
    }
    return o;
  },
  lookAt(o, eye, center, up) {
    const z = vec3.create();
    vec3.sub(z, eye, center); vec3.normalize(z, z);
    const x = vec3.create();
    vec3.cross(x, up, z); vec3.normalize(x, x);
    const y = vec3.create();
    vec3.cross(y, z, x);
    o[0] = x[0]; o[1] = y[0]; o[2] = z[0]; o[3] = 0;
    o[4] = x[1]; o[5] = y[1]; o[6] = z[1]; o[7] = 0;
    o[8] = x[2]; o[9] = y[2]; o[10] = z[2]; o[11] = 0;
    o[12] = -vec3.dot(x, eye);
    o[13] = -vec3.dot(y, eye);
    o[14] = -vec3.dot(z, eye);
    o[15] = 1;
    return o;
