      }
      if (!support) jump = true;
    }
    g.player.update({ forward: true, run: false, jump }, 0, 1/60);
    if (i % 20 === 0 || p.grounded !== prevGrounded) trace.push([i, +p.pos[2].toFixed(2), +p.pos[1].toFixed(2), p.grounded, jump]);
    prevGrounded = p.grounded;
    if (p.pos[1] < -5) { trace.push(['FELL', +p.pos[2].toFixed(2), +p.pos[1].toFixed(2)]); break; }
    if (p.pos[2] < -21) { trace.push(['REACHED_END', +p.pos[2].toFixed(2), +p.pos[1].toFixed(2)]); break; }
  }
  const platformTops = g.level.platforms.map(pl => ({z:+pl.cz.toFixed(2), x:+pl.cx.toFixed(2), top:+pl.topY.toFixed(2)}));
  return { trace, finalZ: g.player.pos[2], finalY: g.player.pos[1], platformTops };
});
