const gapTest = await page.evaluate(async () => {
  const g = window.__game;
  g._reset();
  // Player spawns at z≈2.08 on the start plaza. There is a gap then a block at z=-2.6.
  // Drive forward (-Z) and jump to cross. Run the physics deterministically.
  const log = [];
  let minY = Infinity, tunneled = false;
  // accelerate forward
  for (let i = 0; i < 200; i++) {
    const jump = (i % 45 === 20); // periodic jumps to cross gaps
    g.player.update({ forward: true, run: true, jump }, 0, 1 / 60);
    minY = Math.min(minY, g.player.pos[1]);
    // tunneling = passing below a platform top while horizontally over it
    log.push([+g.player.pos[2].toFixed(2), +g.player.pos[1].toFixed(2), g.player.grounded]);
  }
  const finalZ = g.player.pos[2];
  const finalY = g.player.pos[1];
  g._reset();
  return { finalZ, finalY, minY, reached: finalZ < -2.0, sample: log.filter((_,i)=>i%30===0) };
});
check('5b. Crosses a gap by jumping and lands on far platform (no tunneling)',
  gapTest.reached && gapTest.finalY > -1.0,
  `reached z=${gapTest.finalZ.toFixed(2)}, final y=${gapTest.finalY.toFixed(2)}, minY=${gapTest.minY.toFixed(2)}`);

