  const g=window.__game; const gl=g.renderer.gl;
  // Read the actual UV that the head verts carry, and what texture color is at that UV by
  // sampling the texture via a 1x1 readback through a framebuffer.
  // Simpler: report the texture's actual pixel at the head UV using a canvas2d decode.
  // Instead: list head-region vertices' UVs from the buffer.
  const prim=g.character.primitives[0];
  gl.bindVertexArray(prim.vao);
  const uvBuf=gl.getVertexAttrib(2,gl.VERTEX_ATTRIB_ARRAY_BUFFER_BINDING);
  const posBuf=gl.getVertexAttrib(0,gl.VERTEX_ATTRIB_ARRAY_BUFFER_BINDING);
  gl.bindBuffer(gl.ARRAY_BUFFER,uvBuf);
  const uv=new Float32Array(g.character.gltf.json.accessors[0].count*2);
  gl.getBufferSubData(gl.ARRAY_BUFFER,0,uv);
  gl.bindBuffer(gl.ARRAY_BUFFER,posBuf);
  const pos=new Float32Array(g.character.gltf.json.accessors[0].count*3);
  gl.getBufferSubData(gl.ARRAY_BUFFER,0,pos);
  gl.bindVertexArray(null);
  // find a head vert (Y>0.5, Z>0.1, front)
  let sample=null;
  for(let i=0;i<pos.length/3;i++){
    if(pos[i*3+1]>0.6 && pos[i*3+2]>0.15){ sample={i,pos:[pos[i*3],pos[i*3+1],pos[i*3+2]].map(x=>+x.toFixed(2)),uv:[+uv[i*2].toFixed(3),+uv[i*2+1].toFixed(3)]}; break; }
  }
  return { sample };
});
console.log(JSON.stringify(r));
await browser.close();server.close();
