  mat4.perspective(proj,0.8,aspect,0.1,100);
  // Character faces -Z (facing=PI). Put camera in front of its face at -Z looking back to +?
  // Its front normal points toward -Z, so camera at z=-2 looking toward +z sees the face.
  mat4.lookAt(view,[0,0.5,-2],[0,0.45,0],[0,1,0]);
  gl.clearColor(0.3,0.35,0.45,1); gl.clear(gl.COLOR_BUFFER_BIT|gl.DEPTH_BUFFER_BIT);
  g.character.pose('idle',0);
